final:
module gray_counter_12(
   input                clk,
   input                rst_n,

   output reg [11:0]    Q  
);
    reg [11:0] gray_code_counter;

    always @(posedge clk) begin
        if (!rst_n) gray_code_counter <= 12'b0;
        else gray_code_counter <= gray_code_counter + 1;
    end

    always @(*) begin
        Q = gray_code_counter ^ (gray_code_counter >> 1);
    end
endmodule
